package ui.admin;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import model.*;import util.*;import ui.common.TableStyle;
public class FakeExpiredInternshipsPanel extends JPanel{ JTable table=new JTable(); public FakeExpiredInternshipsPanel(){setBackground(UITheme.BG);setLayout(new BorderLayout());add(UITheme.title("Remove Fake / Expired Internships"),BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER);JButton del=UITheme.button("Delete Selected Internship");add(del,BorderLayout.SOUTH);del.addActionListener(e->del());load();} void load(){DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","Title","Status","Deadline"},0);for(Internship j:new InternshipController().all())m.addRow(new Object[]{j.getId(),j.getTitle(),j.getStatus(),j.getDeadline()});table.setModel(m);TableStyle.apply(table);} void del(){int r=table.getSelectedRow();if(r<0)return;if(DialogUtil.confirm(this,"Delete this internship?")){new InternshipController().delete(Integer.parseInt(table.getValueAt(r,0).toString()));load();}}}
